0 || 'default';    // 'default'（0 是假值）
'' || 'default';   // 'default'（空字符串是假值）

// ?? 只处理 null 和 undefined
0 ?? 'default';    // 0（正确！0 不是 null/undefined）
'' ?? 'default';   // ''（正确！）
null ?? 'default'; // 'default'
undefined ?? 'default'; // 'default'

// 实际场景
const config = { timeout: 0, retries: null };
const timeout = config.timeout ?? 5000;  // 0（正确）
const retries = config.retries ?? 3;     // 3
```

### 逻辑赋值运算符（ES2021）
```js
let a = null;
a ??= 'default'; // a 为 null/undefined 才赋值
console.log(a);  // 'default'

let b = 0;
b ||= 'fallback'; // b 为假值才赋值，b = 'fallback'

let c = 1;
c &&= 2; // c 为真值才赋值，c = 2
```

