## 异步迭代器

### 基本概念
异步迭代器用于处理异步数据流，`next()` 返回 Promise。

```js
// 实现异步迭代器
const asyncRange = {
  from: 1,
  to: 3,
  [Symbol.asyncIterator]() {
    let current = this.from;
    const last = this.to;
    return {
      async next() {
        await new Promise(resolve => setTimeout(resolve, 100)); // 模拟异步
        if (current <= last) {
          return { value: current++, done: false };
        }
        return { value: undefined, done: true };
      }
    };
  }
};

// for await...of
for await (const num of asyncRange) {
  console.log(num); // 1, 2, 3（每隔100ms）
}
```

### 异步 Generator
```js
async function* fetchPages(url) {
  let page = 1;
  while (true) {
    const res = await fetch(`${url}?page=${page}`);
    const data = await res.json();
    if (!data.items.length) return;
    yield data.items;
    page++;
  }
}

for await (const items of fetchPages('/api/list')) {
  console.log(items);
  // 每次 yield 一页数据
}
```

### 实际应用：分页加载
```js
async function* paginate(fetchFn) {
  let cursor = null;
  do {
    const { data, nextCursor } = await fetchFn(cursor);
    yield data;
    cursor = nextCursor;
  } while (cursor);
}

// 使用
for await (const page of paginate(fetchUsers)) {
  renderUsers(page);
}
```

### ReadableStream 异步迭代（现代浏览器）
```js
const response = await fetch('/api/stream');
const reader = response.body.getReader();

// ReadableStream 支持 for await...of
for await (const chunk of response.body) {
  processChunk(chunk);
}
```

## JS 类型系统底层

### typeof 的实现原理
`typeof` 通过检查值的内部类型标签（type tag）工作。

```js
typeof undefined // 'undefined'（tag: 0b000_0001）
typeof null      // 'object'（历史 bug！null 的 tag 是 0，与对象相同）
typeof true      // 'boolean'
typeof 42        // 'number'
typeof 'str'     // 'string'
typeof Symbol()  // 'symbol'
typeof 42n       // 'bigint'
typeof {}        // 'object'
typeof []        // 'object'
typeof function(){} // 'function'（对象的特殊检测）
```

### instanceof 的原理
沿原型链查找，检查 `Constructor.prototype` 是否在对象的原型链上。

```js
const arr = [];
arr instanceof Array;  // true
arr instanceof Object; // true（Array.prototype -> Object.prototype）

// 手写 instanceof
function myInstanceof(obj, Constructor) {
  if (obj === null || typeof obj !== 'object' && typeof obj !== 'function') {
    return false;
  }
  let proto = Object.getPrototypeOf(obj);
  while (proto !== null) {
    if (proto === Constructor.prototype) return true;
    proto = Object.getPrototypeOf(proto);
  }
  return false;
}
```

### instanceof 的局限性
```js
// 跨 iframe 问题：不同 window 的 Array.prototype 不同
const iframe = document.createElement('iframe');
document.body.appendChild(iframe);
const iframeArr = new iframe.contentWindow.Array();
iframeArr instanceof Array; // false！
Array.isArray(iframeArr);   // true ✅（不受跨 iframe 影响）

// Symbol.hasInstance 可以自定义 instanceof 行为
class Even {
  static [Symbol.hasInstance](num) {
    return num % 2 === 0;
  }
}
2 instanceof Even; // true
3 instanceof Even; // false
```

### 最准确的类型判断
```js
function getType(val) {
  return Object.prototype.toString.call(val).slice(8, -1).toLowerCase();
}

getType(null);      // 'null'
getType([]);        // 'array'
getType(new Date()); // 'date'
getType(/reg/);     // 'regexp'
getType(new Map()); // 'map'
```

## Reflect API

### 概述
Reflect 提供了一套操作对象的方法，与 Proxy 的陷阱一一对应，是更现代、更规范的对象操作方式。

### 主要方法

```js
// Reflect.get(target, prop, receiver)
Reflect.get({ x: 1 }, 'x'); // 1
// receiver 用于处理 getter 中的 this

// Reflect.set(target, prop, value, receiver)
const obj = {};
Reflect.set(obj, 'x', 1); // true（返回是否成功）

// Reflect.has(target, prop) -- 对应 in 操作符
Reflect.has({ x: 1 }, 'x');         // true
Reflect.has({ x: 1 }, 'toString');  // true（原型链）

// Reflect.deleteProperty(target, prop) -- 对应 delete
Reflect.deleteProperty(obj, 'x'); // true

// Reflect.ownKeys(target) -- 所有自有键（包括 Symbol）
const sym = Symbol('s');
const o = { a: 1, [sym]: 2 };
Reflect.ownKeys(o); // ['a', Symbol(s)]

// Reflect.apply(target, thisArg, args) -- 对应 Function.prototype.apply
Reflect.apply(Math.max, null, [1, 2, 3]); // 3
Reflect.apply(''.toUpperCase, 'hello', []); // 'HELLO'

// Reflect.construct(target, args, newTarget) -- 对应 new
const arr = Reflect.construct(Array, [1, 2, 3]);

// Reflect.defineProperty -- 对应 Object.defineProperty，但返回 boolean
Reflect.defineProperty(obj, 'y', { value: 2, writable: false });

// Reflect.getOwnPropertyDescriptor
Reflect.getOwnPropertyDescriptor(obj, 'y');

// Reflect.getPrototypeOf / setPrototypeOf
Reflect.getPrototypeOf([]) === Array.prototype; // true
```

### 与 Object 方法的区别
```js
// Object.defineProperty 抛出错误，Reflect.defineProperty 返回 false
try {
  Object.defineProperty(frozen, 'prop', { value: 1 }); // 抛出
} catch (e) {}

const ok = Reflect.defineProperty(frozen, 'prop', { value: 1 }); // false

// Proxy 中配合 Reflect 使用 receiver 保证正确的 this
const proxy = new Proxy(obj, {
  get(target, key, receiver) {
    return Reflect.get(target, key, receiver); // receiver 正确传递
  }
});
```

## IIFE（Immediately Invoked Function Expression）

### 定义
定义后立即执行的函数表达式，用于创建独立作用域。

```js
// 经典写法
(function() {
  var private = 'only in here';
  console.log(private);
})();

// 箭头函数写法
