  var counter = 0;
  // counter 仅在函数内部
})();
```

**2. 模块模式（ES6 前的封装）**
```js
const Counter = (function() {
  let count = 0;
  return {
    increment() { count++; },
    decrement() { count--; },
    value() { return count; }
  };
})();

Counter.increment();
Counter.value(); // 1
```

**3. 避免循环闭包问题（ES5 时代）**
```js
for (var i = 0; i < 3; i++) {
  (function(i) {
    setTimeout(() => console.log(i), 0); // 0 1 2
  })(i);
}
// 现代写法直接用 let
```

**4. 处理异步模块加载**

### 现代替代
在 ES6+ 中，可以用块级作用域 `{}` + `let/const` 或 ES Module 代替 IIFE。

