## Mixin 模式

### 定义
Mixin 是一种将多个对象/类的方法组合到目标对象的技术，用于解决 JavaScript 单继承的限制。

### 对象 Mixin
```js
const Serializable = {
  serialize() {
    return JSON.stringify(this);
  },
  deserialize(json) {
    return Object.assign(this, JSON.parse(json));
  }
};

const Validatable = {
  validate() {
    return Object.values(this).every(v => v !== null && v !== undefined);
  }
};

class User {
  constructor(name, email) {
    this.name = name;
    this.email = email;
  }
}

// 混入方法
Object.assign(User.prototype, Serializable, Validatable);

const user = new User('Alice', 'alice@example.com');
user.serialize();  // '{"name":"Alice","email":"alice@example.com"}'
user.validate();   // true
```

### 函数式 Mixin（更安全）
```js
const withLogging = (Base) => class extends Base {
  log(message) {
    console.log(`[${this.constructor.name}] ${message}`);
  }
};

const withTimestamp = (Base) => class extends Base {
  getTimestamp() {
    return new Date().toISOString();
  }
};

class BaseModel {}
class User extends withTimestamp(withLogging(BaseModel)) {
  constructor(name) { super(); this.name = name; }
}

const user = new User('Alice');
user.log('Created');   // [User] Created
user.getTimestamp();   // ISO 时间戳
```

### 与继承的对比
- 继承是 "is-a" 关系（Dog is an Animal）
- Mixin 是 "has-a" / "can-do" 关系（User can serialize）
- Mixin 避免了多继承的菱形问题

## 递归与优化

### 普通递归的问题
```js
function fib(n) {
  if (n <= 1) return n;
  return fib(n - 1) + fib(n - 2); // 指数级复杂度 O(2^n)
}
fib(40); // 慢！fib(50) 会卡住
```

### 记忆化递归（Memoization）
```js
function memoize(fn) {
  const cache = new Map();
  return function(...args) {
    const key = JSON.stringify(args);
    if (cache.has(key)) return cache.get(key);
    const result = fn.apply(this, args);
    cache.set(key, result);
    return result;
  };
}

const fib = memoize(function(n) {
  if (n <= 1) return n;
  return fib(n - 1) + fib(n - 2);
});

fib(100); // O(n)，极快
```

### 迭代替代递归
```js
// 斐波那契迭代版
function fib(n) {
  let a = 0, b = 1;
  for (let i = 2; i <= n; i++) {
    [a, b] = [b, a + b];
  }
  return n === 0 ? a : b;
}

// 树的深度优先遍历：递归 → 迭代（用栈）
function dfs(root) {
  const stack = [root];
  const result = [];
  while (stack.length) {
    const node = stack.pop();
    result.push(node.val);
    if (node.right) stack.push(node.right);
    if (node.left) stack.push(node.left);
  }
  return result;
}
```

### 动态规划（Bottom-Up）
```js
function fib(n) {
  const dp = [0, 1];
  for (let i = 2; i <= n; i++) {
    dp[i] = dp[i - 1] + dp[i - 2];
  }
  return dp[n];
}

// 空间优化版
function fib(n) {
  if (n <= 1) return n;
  let prev = 0, curr = 1;
  for (let i = 2; i <= n; i++) {
    [prev, curr] = [curr, prev + curr];
  }
  return curr;
}
```

## 函数式编程（FP）

### 核心原则

**1. 纯函数（Pure Function）**
- 相同输入永远得到相同输出
- 没有副作用（不修改外部状态）

```js
// 纯函数
const add = (a, b) => a + b;
const double = arr => arr.map(x => x * 2); // 返回新数组

// 非纯函数
let count = 0;
const increment = () => { count++; }; // 修改外部状态
```

**2. 不可变性（Immutability）**
```js
// 不要修改，而是创建新的
const addUser = (users, user) => [...users, user];
const updateUser = (users, id, updates) =>
  users.map(u => u.id === id ? { ...u, ...updates } : u);
```

**3. 函数组合（Composition）**
```js
const compose = (...fns) => x => fns.reduceRight((v, f) => f(v), x);
const pipe = (...fns) => x => fns.reduce((v, f) => f(v), x);

const transform = pipe(
  x => x.trim(),
  x => x.toLowerCase(),
  x => x.replace(/\s+/g, '-')
);
transform('  Hello World  '); // 'hello-world'
```

**4. 高阶函数（Higher-Order Functions）**
```js
// 接受函数或返回函数
const map = (fn) => (arr) => arr.map(fn);
const filter = (fn) => (arr) => arr.filter(fn);

const doubleAll = map(x => x * 2);
doubleAll([1, 2, 3]); // [2, 4, 6]
```

**5. 避免共享状态**
```js
// 错误：共享 state
let state = { count: 0 };
function increment() { state.count++; }

// 正确：state 流转
const reducer = (state, action) => {
  switch (action.type) {
    case 'INCREMENT': return { ...state, count: state.count + 1 };
    default: return state;
  }
};
```

### 实际应用
```js
// 数据管道
const result = users
  .filter(u => u.age >= 18)
  .map(u => ({ ...u, isAdult: true }))
  .reduce((acc, u) => ({ ...acc, [u.id]: u }), {});
```

## JavaScript 函数重载

### JavaScript 没有原生重载
JS 中同名函数后者会覆盖前者，但可以通过以下方式模拟：

### 方法1：检查参数数量
```js
function createElement(tag, options, children) {
  if (arguments.length === 1) {
    // 只有标签名
    return document.createElement(tag);
  } else if (arguments.length === 2) {
    if (typeof options === 'string') {
      // 第二个参数是 children（字符串）
      const el = document.createElement(tag);
      el.textContent = options;
      return el;
    } else {
      // 第二个参数是 options 对象
      return createElement(tag, options, null);
    }
  }
  // ... 完整实现
}
```

### 方法2：检查参数类型
```js
function process(input) {
  if (typeof input === 'string') {
    return input.toUpperCase();
  } else if (Array.isArray(input)) {
    return input.map(x => x * 2);
  } else if (typeof input === 'number') {
    return input * 2;
  }
  throw new TypeError('Unsupported type');
}
```

### 方法3：选项对象（推荐）
```js
function fetchData({ url, method = 'GET', body = null, timeout = 5000 } = {}) {
  // 通过解构实现灵活参数
}

fetchData({ url: '/api/users' });
fetchData({ url: '/api/users', method: 'POST', body: { name: 'Alice' } });
```

### 方法4：方法分发表
```js
const handlers = {
  string: (v) => v.toUpperCase(),
  number: (v) => v * 2,
  array: (v) => v.flat(),
  object: (v) => JSON.stringify(v)
};

function process(input) {
  const type = Array.isArray(input) ? 'array' : typeof input;
  const handler = handlers[type];
  if (!handler) throw new TypeError(`No handler for ${type}`);
  return handler(input);
}
```

## Atomics 和 SharedArrayBuffer

### SharedArrayBuffer
允许在主线程和 Web Workers 之间共享内存（零拷贝通信）。

```js
// 创建 16 字节共享内存
const sab = new SharedArrayBuffer(16);
const int32 = new Int32Array(sab);

// 传递给 Worker（共享同一内存块）
worker.postMessage({ buffer: sab });
```

### 为什么需要 Atomics？
多线程并发读写同一内存会导致竞态条件（Race Condition）：
```
线程A读: value = 0
线程B读: value = 0
线程A写: value = 1
线程B写: value = 1
结果: 应该是 2，实际是 1！
```

### Atomics API
```js
const sab = new SharedArrayBuffer(4);
const view = new Int32Array(sab);

// 原子加法（线程安全）
Atomics.add(view, 0, 1);    // 原子地 += 1，返回旧值
Atomics.sub(view, 0, 1);    // 原子地 -= 1
Atomics.and(view, 0, 0xFF); // 原子位与
Atomics.or(view, 0, 0x01);  // 原子位或

// 原子读写
Atomics.load(view, 0);         // 原子读取
Atomics.store(view, 0, 42);    // 原子写入，返回写入值

// 比较并交换（CAS，实现锁的基础）
// 如果 view[0] === expectedValue，则写入 newValue
Atomics.compareExchange(view, 0, 0, 1); // 返回旧值

// 等待/通知（类似互斥锁）
// Worker 中等待 view[0] 变为非 0
Atomics.wait(view, 0, 0);   // 阻塞，只能在 Worker 中用
// 主线程通知等待的 Worker
Atomics.notify(view, 0, 1); // 唤醒1个等待者
```

### 简单互斥锁实现
```js
const LOCK_INDEX = 0;

function lock(view) {
  // 自旋锁：不断尝试将 0 改为 1
  while (Atomics.compareExchange(view, LOCK_INDEX, 0, 1) !== 0) {
    Atomics.wait(view, LOCK_INDEX, 1); // 等待解锁
  }
}

function unlock(view) {
  Atomics.store(view, LOCK_INDEX, 0);
  Atomics.notify(view, LOCK_INDEX, 1);
}
```

### 注意事项
- `Atomics.wait` 不能在主线程调用（会阻塞 UI）
- SharedArrayBuffer 需要 COOP/COEP 响应头（安全限制）
- 主要用于高性能计算场景（图像处理、科学计算）
